MERGE INTO CONSULTAS FIN USING (SELECT '002368SubCertificadoCDPCastilla' INFORME ,TO_CLOB(q'[SELECT DISTINCT
    SECTOR.DESCRIPCION NOMBRE_SECTOR,
    PROGRAMA.DESCRIPCION NOMBRE_PROGRAMA,
    PRODUCTO.DESCRIPCION NOMBRE_PRODUCTO,
    COMPONENTES.NOMBRECOMPONENTE COMPONENTE_PROYECTO, 
    COMPONENTES_ACTIVIDADES.DESCRIPCION ACTIVIDAD_PROYECTO,
    BP_D_NOVEDADPROYECTO.RUBROPRESUPUESTAL RUBRO,
    BP_D_NOVEDADPROYECTO.FUENTERECURSOS FUENTE,
    BP_RUBRO_INVERSION_DET.DESCRIPCION NOMBRE_RUBRO,
    BP_D_NOVEDADPROYECTO.VALORSOLICITADO VALOR_SOLICITADO
FROM BP_D_NOVEDADPROYECTO
INNER JOIN BP_RUBRO_INVERSION_DET ON BP_D_NOVEDADPROYECTO.RUBROPRESUPUESTAL = BP_RUBRO_INVERSION_DET.RUBRO AND BP_D_NOVEDADPROYECTO.COMPANIA = BP_RUBRO_INVERSION_DET.COMPANIA
INNER JOIN BP_PLAN_INDICATIVO
    ON BP_D_NOVEDADPROYECTO.COMPANIA      = BP_PLAN_INDICATIVO.COMPANIA
   AND BP_D_NOVEDADPROYECTO.ID_META_PRODUCTO  = BP_PLAN_INDICATIVO.ID
LEFT JOIN BP_PLAN_INDICATIVO  SECTOR
    ON SUBSTR(BP_PLAN_INDICATIVO.ID,1,PCK_SYSMAN_UTL.FC_PAR('s$compania$s','NUMERO DE DIGITOS SECTOR', -1, SYSDATE)) =SECTOR.ID
   AND BP_PLAN_INDICATIVO.COMPANIA = SECTOR.COMPANIA
   AND BP_PLAN_INDICATIVO.VIGENCIA_INICIAL = SECTOR.VIGENCIA_INICIAL
LEFT JOIN BP_PLAN_INDICATIVO  PROGRAMA
    ON SUBSTR(BP_PLAN_INDICATIVO.ID,1,PCK_SYSMAN_UTL.FC_PAR('s$compania$s','NUMERO DE DIGITOS PROGRAMA', -1, SYSDATE)) =PROGRAMA.ID
   AND BP_PLAN_INDICATIVO.COMPANIA = PROGRAMA.COMPANIA
   AND BP_PLAN_INDICATIVO.VIGENCIA_INICIAL = PROGRAMA.VIGENCIA_INICIAL
LEFT JOIN BP_PLAN_INDICATIVO  PRODUCTO
    ON SUBSTR(BP_PLAN_INDICATIVO.ID,1,PCK_SYSMAN_UTL.FC_PAR('s$compania$s','NUMERO DE DIGITOS META-PRODUCTO', -1, SYSDATE)) =PRODUCTO.ID
   AND BP_PLAN_INDICATIVO.COMPANIA = PRODUCTO.COMPANIA
   AND BP_PLAN_INDICATIVO.VIGENCIA_INICIAL = PRODUCTO.VIGENCIA_INICIAL
INNER JOIN PROYECTOS ON BP_D_NOVEDADPROYECTO.PROYECTO = PROYECTOS.CODIGO AND BP_D_NOVEDADPROYECTO.COMPANIA = PROYECTOS.COMPANIA
INNER JOIN COMPONENTES ON BP_D_NOVEDADPROYECTO.COMPONENTE = COMPONENTES.CODIGO AND BP_D_NOVEDADPROYECTO.COMPANIA = COMPONENTES.COMPANIA AND PROYECTOS.CODIGO=COMPONENTES.CODIGOPROYECTO
INNER JOIN COMPONENTES_ACTIVIDADES ON COMPONENTES.CODIGO = COMPONENTES_ACTIVIDADES.COMPONENTE AND COMPONENTES.CODIGOPROYECTO = COMPONENTES_ACTIVIDADES.CODIGOPROYECTO
    AND COMPONENTES.COMPANIA = COMPONENTES_ACTIVIDADES.COMPANIA AND BP_D_NOVEDADPROYECTO.ACTIVIDAD = COMPONENTES_ACTIVIDADES.ACTIVIDAD
WHERE (((BP_D_NOVEDADPROYECTO.COMPANIA) = s$compania$s
AND((BP_D_NOVEDADPROYECTO.TIPOT) = NVL('CDP', ''))                    
AND ((BP_D_NOVEDADPROYECTO.CLASET) = NVL('B', ''))               
AND ((BP_D_NOVEDADPROYECTO.NOVEDAD) = NVL('s$codigo$s', 0))))]') CONSULTA, 52 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);

MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002365CertificadoCDPCastilla' INFORME_PADRE, '002368SubCertificadoCDPCastilla' INFORME_HIJO, 'PR_STRSQL_RUBRO' PARAMETRO ,NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);